import scala.xml._

object ConfigParserService {
  def parseConfig(xmlInput: String): Map[String, String] = {
    val xml = XML.loadString(xmlInput)
    extractSettings(xml, Map.empty)
  }

  private def extractSettings(node: Node, acc: Map[String, String]): Map[String, String] = {
    node match {
      case Elem(_, "setting", attributes, _, _*) =>
        val key = (attributes \ "name").text
        val value = (attributes \ "value").text
        acc + (key -> value)
      case Group(nodes) => nodes.foldLeft(acc)(extractSettings)
      case _ => acc
    }
  }

  def main(args: Array[String]): Unit = {
    // Example usage
    val xmlConfig = """
      |<config>
      |  <setting name="host" value="localhost"/>
      |  <setting name="port" value="8080"/>
      |</config>
    """.stripMargin

    val settings = parseConfig(xmlConfig)
    println(settings)
  }
}